pub fn generate_agent_id(issue: Option<u32>, branch: Option<&str>) -> String {
    if let Some(n) = issue {
        format!("spoke-{n}")
    } else if let Some(b) = branch {
        let slug: String = b
            .chars()
            .take(30)
            .map(|c| if c.is_alphanumeric() { c } else { '-' })
            .collect();
        format!("spoke-{slug}")
    } else {
        format!("spoke-{}", &uuid::Uuid::new_v4().to_string()[..8])
    }
}
